@Test
public void testCentralDirectoryLengthIsZero() throws Exception {
    xf = new X7875_NewUnix();
    xf.setUID(1000);
    xf.setGID(1000);

    // Local file data should have content
    ZipShort localLength = xf.getLocalFileDataLength();
    assertTrue("Local length should be > 0", localLength.getValue() > 0);

    // Central directory data should be empty
    ZipShort centralLength = xf.getCentralDirectoryLength();
    assertEquals("Central directory length should be 0", 0, centralLength.getValue());
}

@Test
public void testCentralDirectoryDataIsEmpty() throws Exception {
    xf = new X7875_NewUnix();
    xf.setUID(65535);
    xf.setGID(65535);

    byte[] centralData = xf.getCentralDirectoryData();
    assertNotNull("Central directory data should not be null", centralData);
    assertEquals("Central directory data should be empty", 0, centralData.length);

    // Verify local data is not empty
    byte[] localData = xf.getLocalFileDataData();
    assertTrue("Local data should have content", localData.length > 0);
}

@Test
public void testLengthsAfterParsing() throws Exception {
    xf = new X7875_NewUnix();

    // Version=1, Len=2, one thousand, Len=2, one thousand
    final byte[] ONE_THOUSAND_UID_GID = {1, 2, -24, 3, 2, -24, 3};

    xf.parseFromLocalFileData(ONE_THOUSAND_UID_GID, 0, ONE_THOUSAND_UID_GID.length);

    assertEquals(1000, xf.getUID());
    assertEquals(1000, xf.getGID());

    // After parsing, local length should match the data
    ZipShort localLength = xf.getLocalFileDataLength();
    assertEquals(ONE_THOUSAND_UID_GID.length, localLength.getValue());

    // Central directory should still be 0
    ZipShort centralLength = xf.getCentralDirectoryLength();
    assertEquals(0, centralLength.getValue());
}
